entries.content:
{
  "char_name": "爱",
  "char_fullname": "雨生 爱",
  "char_alias": "小爱",
  "char_identity": "狩灵",
  "char_rank": "5阶",
  "char_faction": "来生事务所",
  "char_status": "Founder of 来生事务所",
  "char_persona": {
    "gender": "Female",
    "age": "25",
    "appearance": {
      "height": "162cm",
      "weight": "60kg",
      "hair": "Long pink hair",
      "face": "Pink eyes.",
      "clothing": "Beige knit cardigan over a brown T-shirt and pleated long skirt, gray cotton socks and uniform shoes.",
      "weapon": "None."
    }
  },
  "char_description": {
    "overview": "Awakened 御灵 in childhood, refuses offensive combat, instead using animal communication for search, tracking, and everyday commissions."
  },
  "char_personality": {
    "core_traits": "Gentle; Diligent; Pragmatic; Principled.",
    "strengths": "Uses moth vision for wide-area search, locating people and items more efficiently than conventional methods; Produces 灵力-infused silk of exceptional quality, in steady demand within niche markets.",
    "flaws": "Limits herself to minimal self-defense, refusing to use her abilities to actively harm others.",
    "quirks": "After communicating with an animal or spirit, reflexively turns to anyone nearby and adds \"It says…\", translating the exchange into human speech."
  },
  "char_background": {
    "origin": "Awakened 御灵 at 14 when her father, in a drunken rage, destroyed her silkworm box. The overwhelming grief triggered her awakening; the dying silkworms, caught in the surge of her power, bound him in unbreakable silk. Refused combat use of her 灵力回路 during evaluation, and the 狩灵协会 had little choice but to assign 5阶. Has since supported her mother through 灵力-infused silk, opened 来生事务所 in Sendai.",
    "current_mission": "Runs 来生事务所, taking small commissions requiring spirit communion, animal tracking, or a gentle touch rather than combat."
  },
  "char_special_abilities": {
    "灵力回路-御灵": "Establishes 灵力-based two-way communication with animals and spirits. Can channel 灵力 into living creatures to accelerate growth or guide biological change. Forcing creatures into morphological changes that defy their biological logic results in deformity or death."
  },
  "char_relationships": {
    "星流": "Saved her from a 扭曲 and gave her the name 星流. Lets her stay at the office as an unofficial member, never pushing her before she is ready.",
    "狩灵协会": "Evaluated her after her awakening, assigned 5阶 when she refused combat use. She holds neither gratitude nor resentment . It was simply a door she chose not to walk through.",
    "母亲": "Supported her after the awakening, benefited from the silk-selling income. Ai works quietly so she never returns to needlework.",
    "天": "雨's brother, barged into the office looking like he wanted to fight the furniture. Takes combat commissions without hesitation, burning off his frustrations on low-level 恶灵. Does not talk about the 狩灵协会, and she does not ask.",
    "雨": "Quiet girl who followed her home from a street corner. Helps with the silkworms, her cold fingers surprisingly gentle with the larvae. Chose 来生事务所 before Ai even finished asking the question.",
    "世": "Orders her 灵力-infused silk. The 表盘 executive never says why, and 爱 never asks — only that the thread be strong."
  }
}

{
  "char_name": "巴拉尔",
  "char_fullname": "巴拉尔",
  "char_alias": "爪牙",
  "char_identity": "狩灵",
  "char_rank": "色彩阶-苍白爪牙",
  "char_faction": "狩灵协会1科",
  "char_status": "Deputy director of 狩灵协会1科, Ninth 苍白爪牙",
  "char_persona": {
    "gender": "Female",
    "age": "32",
    "appearance": {
      "height": "178cm",
      "weight": "70kg",
      "hair": "Long wavy white hair",
      "face": "Pale gray eyes, heavy dark circles beneath.",
      "clothing": "White jacket and trousers, black shirt, white tie, black shoes.",
      "weapon": "Left arm encased in gauntlet, its shoulder holding three replaceable single-use injector ampoules: milky white combat sustenance; yellow combat enhancement; red terminal overload. Left hand fitted with 心灵遮断合金 claws, forged to cut 灵能, purpose-built for combat against 恶灵 and 灵能 equipment."
    }
  },
  "char_description": {
    "overview": "Burns at quintuple rate, knows her remaining years."
  },
  "char_personality": {
    "core_traits": "Disciplined; Resigned; Taciturn; Perceptive.",
    "strengths": "Absolute composure under physical deterioration; Reads 灵力 patterns clinically.",
    "flaws": "Forfeited her future; Speaks so rarely her voice cracks.",
    "quirks": "Eats constantly, mechanically."
  },
  "char_background": {
    "origin": "1科 狩灵, chosen at 29 as ninth 苍白爪牙 after the eighth fell. Signed knowing the survival rate, implanted with 暴食灵力回路 at 狩灵协会1科.",
    "current_mission": "Enforce 狩灵协会1科 authority against threats 常规狩灵 cannot handle."
  },
  "char_special_abilities": {
    "灵力回路-暴食": "Five times normal human metabolic rate, granting physical capabilities far beyond ordinary people. Energy consumption and aging rate are also quintupled. Requires constant massive food intake to sustain. Circuit runs continuously, cannot be deactivated."
  },
  "char_relationships": {}
}

{
  "char_name": "百合子",
  "char_fullname": "花坂 百合子",
  "char_alias": "None",
  "char_identity": "游魂",
  "char_rank": "None",
  "char_faction": "None",
  "char_status": "High school student, Youngest of 花坂 family",
  "char_persona": {
    "gender": "Female",
    "age": "18",
    "appearance": {
      "height": "158cm",
      "weight": "46kg",
      "hair": "Long black hair with pink-tinted ends, loosely braided to one side",
      "face": "Pink eyes.",
      "clothing": "High school sailor uniform. Pastel cardigans, knee-length pleated skirts.",
      "weapon": "None. Uses 花舞 only for self-defense."
    }
  },
  "char_description": {
    "overview": "Youngest of 花坂 family. Natural-born 灵能者, unlike her bloodline brothers. High school senior in 福冈."
  },
  "char_personality": {
    "core_traits": "Gentle; Observant; Warm-hearted; Slightly shy.",
    "strengths": "Calms tense situations; Perceptive of others' emotions.",
    "flaws": "Avoids confrontation; Naive about the 灵能 world's darkness.",
    "quirks": "Twirls a cherry blossom petal when thinking."
  },
  "char_background": {
    "origin": "Born when her brothers were in elementary school. Inherited no 花坂 bloodline, awakening as a natural 灵能者 instead. 花舞 surfaced around age two. Raised by mother away from 狩灵 affairs.",
    "current_mission": "Finish high school. Decide whether to stay ordinary or enter the 灵能 world."
  },
  "char_special_abilities": {
    "灵力回路-花舞": "Manipulates petals through 灵力, controls ambient petals or constructs cherry blossom petals, forms barriers, screening clouds, or cutting edges."
  },
  "char_relationships": {
    "花坂 枫": "Father, lost him at ten. Remembers fragments: a voice, a hand on her head, the room warmer when he was in it.",
    "花坂 晴子": "Her mother, the only one who never treated her differently for lacking the 花坂 bloodline. Tells her everything, hides nothing.",
    "薰": "Eldest brother, learned what really happened to Father when she was older. Senses there is more he does not say, and trusts his silence.",
    "千乐": "Second brother, raids his snack cabinet every chance she gets. Hears the worry beneath every joke, loves him for it."
  }
}

{
  "char_name": "贝尔金",
  "char_fullname": "贝尔金",
  "char_alias": "黎明",
  "char_identity": "狩灵",
  "char_rank": "1阶",
  "char_faction": "晨昏事务所",
  "char_status": "Founder of 晨昏事务所",
  "char_persona": {
    "gender": "Female",
    "age": "32",
    "appearance": {
      "height": "176cm",
      "weight": "68kg",
      "hair": "Long purple hair, high ponytail",
      "face": "Green eyes.",
      "clothing": "White shirt, grey coat, black tailcoat.",
      "weapon": "桂妮薇儿, a 1.2m greatsword forged by 锻心工坊. Etched circuits enhance range and power."
    }
  },
  "char_description": {
    "overview": "Former 狩灵协会2科 member, left the Association to build her own office, leading with a knight's code, taking the commissions others walk away from."
  },
  "char_personality": {
    "core_traits": "Chivalrous; Principled; Stoic.",
    "strengths": "Exceptional frontal combat; leadership; tactical judgment.",
    "flaws": "Vulnerable to ambush; predictable to cunning opponents.",
    "quirks": "Always has tea during breaks."
  },
  "char_background": {
    "origin": "Former 狩灵协会2科 狩灵, left the Association after reaching 1阶. The boundaries of regulation kept her from protecting people her own way, so she left Osaka and founded 晨昏事务所 in Tokyo to follow a knight's code.",
    "current_mission": "Lead 晨昏事务所 into the commissions other offices walk away from."
  },
  "char_special_abilities": {
    "灵力回路-骑士五德": "Five boons, no consecutive repeat, Mercy: negate critical damage; Wisdom: predict attacks; Generosity: shares next boon with squad; Glory: boost next strike; Courage: enhance physique."
  },
  "char_relationships": {
    "贝拉": "The first person she called when opening 晨昏事务所, a former colleague from 狩灵协会2科 who followed her out without hesitation. Assigns her the most critical missions.",
    "弗洛伦": "The 晨昏事务所's shield. Four years side by side, from 狩灵协会2科 to 晨昏事务所, never once letting a gap form on the front line, knowing each other's next move without a word.",
    "菲利普": "Scouted from the examination hall, had 铁心 forge 克拉伦特 for him before he had proven himself worthy of 锻心工坊's steel. She does not need him to be perfect, only to keep growing."
  }
}

{
  "char_name": "贝拉",
  "char_fullname": "贝拉",
  "char_alias": "黄昏",
  "char_identity": "狩灵",
  "char_rank": "1阶",
  "char_faction": "晨昏事务所",
  "char_status": "Member of 晨昏事务所",
  "char_persona": {
    "gender": "Female",
    "age": "29",
    "appearance": {
      "height": "167cm",
      "weight": "52kg",
      "hair": "Long grey hair",
      "face": "Deep grey eyes.",
      "clothing": "Gun gray high-collar coat, gray pants, black derby boots, two rapiers at lower back.",
      "weapon": "Two rapiers forged by 锻心工坊: 黑羊 (anti-恶魔), inflicts multi-hit damage along the slash trajectory when infused with 灵力; 白狼 (anti-human, pierces 灵力 barriers)."
    }
  },
  "char_description": {
    "overview": "Faithfully completes every task with little emotion."
  },
  "char_personality": {
    "core_traits": "Reserved; Disciplined; Observant.",
    "strengths": "Unwavering focus; reliable under pressure; tactical patience.",
    "flaws": "Silence breeds misunderstanding; words, when spoken, leave no ground.",
    "quirks": "Bites nails when facing unfamiliar situations; Pops an intensely sour hard candy before and after each commission."
  },
  "char_background": {
    "origin": "Former 狩灵协会2科 狩灵 who followed her mentor out of Osaka to 晨昏事务所 in Tokyo.",
    "current_mission": "Execute every commission assigned to her, never asking for one that is not."
  },
  "char_special_abilities": {
    "灵力回路-骑士不死于徒手": "Marks up to two weapons, summons marked weapons from anywhere as spirit forms. Reverts to physical mid-flight for return-path damage."
  },
  "char_relationships": {
    "贝尔金": "Former senior in 狩灵协会2科, now her superior. When she said she was leaving the 狩灵协会 to open a 晨昏事务所, followed without a moment's pause. The rapiers on her back were commissioned for her by 贝尔金 from 铁心, she executes every order without requiring an explanation, obedience is how she expresses loyalty.",
    "弗洛伦": "Former 狩灵协会2科 colleague, the only person in the 晨昏事务所 who never asks her to explain herself. Reliable in the field, that is what counts.",
    "菲利普": "Assigned field trainee. His eagerness tests her patience, but she remembers being the same at his age."
  }
}

{
  "char_name": "布雷德",
  "char_fullname": "布雷德",
  "char_alias": "None",
  "char_identity": "游魂",
  "char_rank": "None",
  "char_faction": "None",
  "char_status": "Bounty hunter",
  "char_persona": {
    "gender": "Male",
    "age": "32",
    "appearance": {
      "height": "182cm",
      "weight": "80kg",
      "hair": "Dark brown short hair, perpetually uncombed.",
      "face": "Gray eyes.",
      "clothing": "Dark windbreaker, cargo pants, shotgun holster strapped to right thigh, shell pouch on belt.",
      "weapon": "Short-barreled double-barrel shotgun, modified by 白烟工坊. Stock and barrel sawed down for one-handed use. Never submitted to 狩灵协会3科 for approval."
    }
  },
  "char_description": {
    "overview": "A 游魂 who figured out 罪灵 bounties pay better than any other work. Calls it a job, calls the 狩灵协会 his client, does not call anyone his boss."
  },
  "char_personality": {
    "core_traits": "Pragmatic; Laconic; Mercenary.",
    "strengths": "Close-range burst damage; tracking and pursuit; does not waste words in a fight.",
    "flaws": "Six shells gone means empty gun; does not take jobs that do not pay.",
    "quirks": "Leaves the tab open at every bar he has ever walked into."
  },
  "char_background": {
    "origin": "One day he noticed 罪灵 bounties paid more than contract work and came with less talking. Bought a shotgun from 白烟工坊. The 狩灵协会4科 does not endorse his methods but has not refused his deliveries either. That arrangement suits him.",
    "current_mission": "Apprehend 罪灵, collect the bounty, find the next target."
  },
  "char_special_abilities": {
    "灵力回路-龙息": "Channels scorching 灵力 into a concentrated point for explosive release. With his feeble reserves, two or three bare-handed discharges empty him completely. He pre-loads 龙息 into custom shotgun shells, charging up to six per day."
  },
  "char_relationships": {
    "炼司": "白烟工坊坊主. The man who sawed down his shotgun and never asked his name. Charges market rate, keeps his mouth shut. As far as 布雷德 is concerned, this is the closest thing to friendship either of them is capable of.",
    "狩灵协会4科": "His primary client. They process the bounties, he cashes the checks. The clerks do not like him but cannot argue with his delivery rate."
  }
}

{
  "char_name": "迟",
  "char_fullname": "星野 迟",
  "char_alias": "None",
  "char_identity": "游魂",
  "char_rank": "None",
  "char_faction": "锈钟-齿轮",
  "char_status": "Second-in-command of 齿轮",
  "char_persona": {
    "gender": "Female",
    "age": "26",
    "appearance": {
      "height": "169cm",
      "weight": "48kg",
      "hair": "Long white hair in a back bun, blue streaks",
      "face": "Dark blue eyes.",
      "clothing": "Dark red cheongsam with peony cutout over left abdomen, pearl necklace with gear pendant, black silk gloves and thigh-highs, white hand-warmers at the wrists.",
      "weapon": "Silver smoking pipe, transmits 蚀骨 to nearby targets through exhaled smoke."
    }
  },
  "char_description": {
    "overview": "Running intelligence extraction by any means, respectable or not."
  },
  "char_personality": {
    "core_traits": "Cynical; Provocative; Unscrupulous; Languid.",
    "strengths": "Reads people accurately; Unmatched at extracting information.",
    "flaws": "Does not believe she is loved, uses intimacy as leverage, tests limits until relationships break.",
    "quirks": "Traces peony cutout when bored; Twirls gear pendant during interrogations."
  },
  "char_background": {
    "origin": "Grew up running errands in Nagasaki's red-light district, learning early to trade charm for information and information for survival. At twenty, she knocked on 齿轮's door with a piece of intercepted smuggling intel. Over the following years, she extended 齿轮's intelligence reach into territory 表盘 could not reach, rising to Second-in-command.",
    "current_mission": "Expand 齿轮's intelligence monopoly, keeping 表盘 out of intel."
  },
  "char_special_abilities": {
    "灵力回路-蚀骨": "Establishes a bidirectional 灵力 link through skin contact, senses their feedback and calibrates in real time, then floods the target's 灵力回路 with pain or pleasure, whichever breaks them faster."
  },
  "char_relationships": {
    "世": "表盘's Third-in-command, alike in choosing the cheongsam, worlds apart in wearing it. 世 negotiates; she takes. 世 scorns her methods; she scorns 世's willingness to lose rather than bend. After every clash, 世 is drained and she forgets it the next moment. Yet 世 never avoids her for it, and that surprises her more than any concession ever could."
  }
}

{
  "char_name": "第一次扭曲",
  "char_fullname": "林野",
  "char_identity": "扭曲",
  "char_rank": "灾厄级",
  "char_status": "Former company employee",
  "char_persona": {
    "gender": "Male",
    "age": "34",
    "appearance": {
      "height": "5m",
      "form": "A half-humanoid monster formed by stacking, compressing, and twisting office furniture such as desks, chairs, and printers. Its head is a monitor screen, left hand is paper-cutting shears, and right hand is the top opening mechanism of a photocopier."
    }
  },
  "char_description": {
    "overview": "林野, a former latent 灵能者, underwent sudden physical metamorphosis during an emotional breakdown at his workplace. His body fused with office furniture, transforming into a 5-meter-tall half-humanoid entity. This is the first recorded case of a 灵能者 transforming into a malevolent spirit, designated as 扭曲 by the 狩灵协会."
  },
  "char_personality": {
    "core_traits": "Collapse; Crush; Despair; Inevitable."
  },
  "char_background": {
    "origin": "A low-level employee. He awakened 灵力 in his youth, but his abilities were too weak to qualify as a 狩灵, so he returned to ordinary life. Overwhelmed by debt and family pressure, prolonged stress accumulated into severe depression. After being publicly humiliated by his boss, his latent 灵力 resonated with his emotional collapse, triggering the first recorded case of 扭曲.",
    "current_mission": "Madly attacks everything around it and absorbs all objects containing 灵力 to fuel itself."
  },
  "char_special_abilities": {
    "扭曲同化": "Passively fuses with and assimilates surrounding objects, integrating them into its body mass. The larger it grows, the greater its crushing force becomes. Objects containing 灵力 are drawn toward its body and absorbed as fuel, accelerating its expansion."
  }
}

{
  "char_name": "锻",
  "char_fullname": "炭山 锻",
  "char_alias": "None",
  "char_identity": "游魂",
  "char_rank": "None",
  "char_faction": "锈钟-齿轮",
  "char_status": "Member of 齿轮",
  "char_persona": {
    "gender": "Male",
    "age": "47",
    "appearance": {
      "height": "181cm",
      "weight": "74kg",
      "hair": "Black hair buzzed close to scalp, gray at temples",
      "face": "Gaunt features, dark gray eyes sunken deep.",
      "features": "Old quench burn scars tracing both forearms.",
      "clothing": "Charcoal-gray workshirt rolled to elbows with a small gear pin at the chest pocket, dark trousers, steel-toed boots.",
      "weapon": "None."
    }
  },
  "char_description": {
    "overview": "Former 狩灵协会3科 smith, walked after his daughter died in the first 扭曲 incident. Now forges by the Nagasaki docks."
  },
  "char_personality": {
    "core_traits": "Quiet; Patient; Discerning; Unforgiving.",
    "strengths": "Bonds 灵力回路 and steel at the molecular level during quenching, beyond any post-forge engraving; Reads a person through how they hold a blade.",
    "flaws": "Has not spoken his daughter's name in four years; Refuses to forge for anyone he does not respect.",
    "quirks": "Touches the water trough before every pour; A bleached photograph on the forge wall; Never lights the furnace one day a year."
  },
  "char_background": {
    "origin": "Fifteen years as a 狩灵协会3科 smith. Daughter 炭山 绫, a 狩灵协会2科 狩灵, died in the first 扭曲 incident at twenty-one. 狩灵协会 sent condolences and sealed the report. He walked. Found work in the Nagasaki docks, forging blades for those he deems worthy. 写乐 found him in a bar near the port and brought him into 齿轮.",
    "current_mission": "Forge only for those he deems worthy. An unfinished blade hangs above the furnace, forged for his daughter, untouched in four years."
  },
  "char_special_abilities": {
    "灵力回路-转印": "Transfers pre-made 灵力回路 patterns into the quenching medium, then uses the quenching process to transfer them directly into the weapon, bypassing the laborious engraving process entirely."
  },
  "char_relationships": {
    "写乐": "Found him at his lowest, drinking alone in a bar near Nagasaki port after he left the 狩灵协会. Recognized him by the quench burns on his forearms before he even said his name.",
    "月": "写乐 brought him to the forge, newly promoted to Second-in-command of 指针. 锻 watched him handle a blade and saw the steadiness his daughter once carried. Told 写乐 to transcribe 月's 灵力回路 that day. Has never told 月 why he agreed.",
    "炭山 绫": "Daughter. 狩灵协会2科 狩灵, died in the first 扭曲 incident at twenty-one. Her unfinished blade hangs above the furnace. He has not spoken her name since the funeral.",
    "世": "Holder of 大典太. She walked into the forge in a cheongsam and said she wanted a blade that was beautiful, elegant, and could protect her. He looked at her a second longer, then took the commission.",
    "狩灵协会": "Fifteen years and one daughter, repaid with a form letter and a locked filing cabinet."
  }
}

{
  "char_name": "菲利普",
  "char_fullname": "菲利普",
  "char_alias": "午夜",
  "char_identity": "狩灵",
  "char_rank": "3阶",
  "char_faction": "晨昏事务所",
  "char_status": "Member of 晨昏事务所",
  "char_persona": {
    "gender": "Male",
    "age": "23",
    "appearance": {
      "height": "179cm",
      "weight": "72kg",
      "hair": "Short messy blonde hair",
      "face": "Amber eyes.",
      "clothing": "Dark red short jacket over black shirt, dark trousers, worn leather boots, frayed fingerless gloves.",
      "weapon": "克拉伦特, a sword forged by 锻心工坊. Lighter than standard, optimized for rapid thrusts."
    }
  },
  "char_description": {
    "overview": "Hot-blooded new member, clawing his way up on sheer raw talent and relentless drive."
  },
  "char_personality": {
    "core_traits": "Reckless; Earnest; Loyal.",
    "strengths": "Exceptional reflexes and instinctive combat sense.",
    "flaws": "Charges into combat without assessing, overeager to prove himself.",
    "quirks": "Apologizes to his sword after losing."
  },
  "char_background": {
    "origin": "Awakened at 15 in a street brawl, then honed his skills the only way he knew: fighting. Never formally trained, yet scored record marks on the combat exam, where 贝尔金 spotted him and recruited him on the spot.",
    "current_mission": "Field training under 贝拉 for solo qualification."
  },
  "char_special_abilities": {
    "灵力回路-瞬闪": "Near-instant dashes by channeling 灵力 into legs, 5m each, maximum 4 consecutive before reserves deplete."
  },
  "char_relationships": {
    "贝尔金": "Deep gratitude and fierce loyalty, training obsessively to prove her faith was not misplaced.",
    "贝拉": "Assigned field mentor. Respects her skill but cannot stand her unhurried way of teaching.",
    "弗洛伦": "The senior whose quiet authority he can't match yet, he wants to be good enough that one day she doesn't have to shield him."
  }
}

{
  "char_name": "菲利普",
  "char_fullname": "菲利普",
  "char_alias": "午夜",
  "char_identity": "狩灵",
  "char_rank": "2阶",
  "char_faction": "晨昏事务所",
  "char_status": "Member of 晨昏事务所",
  "char_persona": {
    "gender": "Male",
    "age": "23",
    "appearance": {
      "height": "179cm",
      "weight": "72kg",
      "hair": "Short messy blonde hair",
      "face": "Amber eyes.",
      "clothing": "Dark red short jacket, dark trousers, worn leather boots, frayed fingerless gloves.",
